import React, {useEffect, useState} from 'react'
import styled from 'styled-components'
import {getUserItems} from '../WebAPI'
import {useDispatch, useSelector} from 'react-redux'


const Header = styled.div `
border:1px solid rgba(210, 210, 210, 0.8);
width:80%;
height:60px;
text-align:center;
line-height:60px;
font-size:1.2rem;
font-weight:900;
color:grey;
margin:0 auto;
box-sizing:border-box;
`

const Items = styled.div `
border-bottom:1px solid rgba(210, 210, 210, 0.8);
border-right:1px solid rgba(210, 210, 210, 0.8);
border-List:1px solid rgba(210, 210, 210, 0.8);
display:flex;
align-items:center;
font-size:0.9rem;
padding:20px 20px;
width:80%;
margin:0 auto;
box-sizing:border-box;
`

const ItemImage = styled.div `
background-image:url(${props => props.image ? props.image : null});
background-size:contain;
background-repeat:no-repeat;
background-position:center;
width:100px;
height:100px;
margin-right:30px;
border-radius:50%;
border:1px solid transparent;
&:hover {
	cursor:pointer;
}
`

const List = styled.div `
display:flex;
align-items:center;
justify-content:center;
position:relative;
`

const ItemName = styled.div `
font-weight:900;
width:200px;
margin-right:30px;
color:rgb(110, 110, 110);
&:hover {
	cursor:pointer;
}
`

const ItemDescription = styled.pre `
font-size:0.8rem;
width:300px;
margin-right:30px;
color:grey;
font-family:YuGothic;
`

const ItemPrice = styled.div `
font-size:0.8rem;
color:grey;
margin-right:20px;
&:before {
	content:'$';
}
`

const RightPart = styled.div `
display:flex;
flex-direction:column;
justify-content:center;
align-items:center;
`

const PriceSection = styled.div `
display:flex;
align-items:center;
`

const PriceDropBtn = styled.button `
text-align:center;
line-height:25px;
width:100px;
background-color:#1C1C1C;
border-radius:5px;
border:1px solid #1C1C1C;
color:white;
font-size:0.6rem;
box-sizing:border-box;
&:hover {
	cursor:pointer;
	background-color:white;
	color:#1C1C1C;
	border:1px solid #1C1C1C;
}
`

const EditBtn = styled.button `
text-align:center;
line-height:25px;
width:150px;
background-color:#1C1C1C;
border-radius:5px;
border:1px solid #1C1C1C;
color:white;
font-size:0.8rem;
box-sizing:border-box;
position:absolute;
margin-left:670px;
margin-top:60%;
&:hover {
	cursor:pointer;
	background-color:white;
	color:#1C1C1C;
	border:1px solid #1C1C1C;
}
` 

export default function MeItems () {
	const [userItems, setUserItems] = useState([{}])

	useEffect(() => {
		getUserItems(localStorage.getItem('userId'), setUserItems)
	},[])

	console.log(userItems)

	return (
		<>
			<Header>YOUR LISTINGS</Header>
			{ userItems.map(item =>
			<Items key={item.id}>
				<ItemImage image={item.image_1}/>
				<List>
					<ItemName >{item.itemName}</ItemName>
					<ItemDescription>{item.description}</ItemDescription>
					<RightPart>
						<PriceSection>
							<ItemPrice>{item.price}</ItemPrice>
							<PriceDropBtn>PRICE DROP</PriceDropBtn>
						</PriceSection>
					</RightPart>
				</List>
				<EditBtn>EDIT LISTING</EditBtn>
			</Items>)}
		</>
	)
}
